  width: 100%;
  height: 100%;
  vertical-align: top;
}

.el-empty__description {
  margin-top: var(--el-empty-description-margin-top);
}
.el-empty__description p {
  margin: 0;
  font-size: var(--el-font-size-base);
  color: var(--el-text-color-secondary);
}

